	private static final class RecordingBanditPolicy implements BanditPolicy {

		private final List<ReportedOutcome> reports = new CopyOnWriteArrayList<>();

		@Override
		public List<String> selectPlanners(String regionFingerprint, List<String> available, int k) {
			if (available == null || available.isEmpty()) {
				return List.of();
			}
			int limit = Math.max(1, Math.min(k, available.size()));
			return available.subList(0, limit);
		}

		@Override
		public void reportOutcome(String regionFingerprint, String chosenPlanner, double reward) {
			reports.add(new ReportedOutcome(regionFingerprint, chosenPlanner, reward));
		}
	}

	private static final class ReportedOutcome {
		private final String regionFingerprint;
		private final String planner;
		private final double reward;

		private ReportedOutcome(String regionFingerprint, String planner, double reward) {
			this.regionFingerprint = regionFingerprint;
			this.planner = planner;
			this.reward = reward;
		}
	}
